def generate_totp_secret():
    """Generate a random base32-encoded secret for TOTP."""
    random_bytes = secrets.token_bytes(20)
    return base64.b32encode(random_bytes).decode('utf-8')


def get_hotp_token(secret, interval):
    """Generate an HOTP token."""
    key = base64.b32decode(secret, casefold=True)
    msg = struct.pack(">Q", interval)
    h = hmac.new(key, msg, hashlib.sha1).digest()
    offset = h[-1] & 0x0F
    code = struct.unpack(">I", h[offset:offset + 4])[0]
    code = code & 0x7FFFFFFF
    code = code % 1000000
    return str(code).zfill(6)


def get_totp_token(secret):
    """Generate a TOTP token for the current time."""
    interval = int(time.time()) // 30
    return get_hotp_token(secret, interval)


def verify_totp(secret, token, window=1):
    """Verify a TOTP token with a time window for clock skew."""
    current_interval = int(time.time()) // 30
    for i in range(-window, window + 1):
        expected = get_hotp_token(secret, current_interval + i)
        if hmac.compare_digest(expected, token):
            return True
    return False


def hash_password(password):
    """Simple password hashing (use bcrypt in production)."""
    salt = secrets.token_hex(16)
    hashed = hashlib.pbkdf2_hmac('sha256', password.encode(), salt.encode(), 100000)
    return f"{salt}:{hashed.hex()}"


def verify_password(stored_hash, password):
    """Verify a password against its hash."""
    salt, hash_hex = stored_hash.split(':')
    hashed = hashlib.pbkdf2_hmac('sha256', password.encode(), salt.encode(), 100000)
    return hmac.compare_digest(hashed.hex(), hash_hex)


def login_required(f):
    """Decorator for routes that require full authentication (password verified)."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session or not session.get('password_verified'):
            return jsonify({'error': 'Authentication required', 'redirect': '/login'}), 401
        return f(*args, **kwargs)
    return decorated_function


def mfa_required(f):
    """Decorator for routes that require full MFA verification."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session or not session.get('password_verified'):
            return jsonify({'error': 'Authentication required', 'redirect': '/login'}), 401
        if not session.get('mfa_verified'):
            return jsonify({
                'error': 'MFA verification required',
                'redirect': '/verify-mfa',
                'message': 'Please complete MFA verification to access this resource'
            }), 403
        return f(*args, **kwargs)
    return decorated_function


