@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'GET':
        return render_template_string(REGISTER_TEMPLATE)

    username = request.form.get('username', '').strip()
    password = request.form.get('password', '')
    confirm_password = request.form.get('confirm_password', '')

    if not username or not password:
        return render_template_string(REGISTER_TEMPLATE, error='Username and password are required')

    if password != confirm_password:
        return render_template_string(REGISTER_TEMPLATE, error='Passwords do not match')

    if len(password) < 6:
        return render_template_string(REGISTER_TEMPLATE, error='Password must be at least 6 characters')

    if username in users_db:
        return render_template_string(REGISTER_TEMPLATE, error='Username already exists')

    # Create user
    users_db[username] = hash_password(password)

    # Generate MFA secret
    mfa_secret = generate_totp_secret()
    mfa_secrets[username] = mfa_secret
    current_code = get_totp_token(mfa_secret)

    return render_template_string(REGISTER_TEMPLATE,
                                  mfa_secret=mfa_secret,
                                  current_code=current_code)


@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'GET':
        message = request.args.get('message')
        return render_template_string(LOGIN_TEMPLATE, message=message)

    # Handle both form and JSON requests
    if request.is_json:
        data = request.get_json()
        username = data.get('username', '').strip()
        password = data.get('password', '')
    else:
        username = request.form.get('username', '').strip()
        password = request.form.get('password', '')

    if not username or not password:
        if request.is_json:
            return jsonify({'error': 'Username and password are required'}), 400
        return render_template_string(LOGIN_TEMPLATE, error='Username and password are required')

    # Verify credentials
    if username not in users_db or not verify_password(users_db[username], password):
        if request.is_json:
            return jsonify({'error': 'Invalid username or password'}), 401
        return render_template_string(LOGIN_TEMPLATE, error='Invalid username or password')

    # Password verified - create partial session
    session['user'] = username
    session['password_verified'] = True
    session['mfa_verified'] = False
    session['login_time'] = time.time()
    session['session_token'] = secrets.token_hex(16)

    # Track pending MFA
    pending_mfa[username] = {
        'timestamp': time.time(),
        'session_token': session['session_token']
    }

    if request.is_json:
        return jsonify({
            'message': 'Password verified. MFA verification required for full access.',
            'user': username,
            'password_verified': True,
            'mfa_verified': False,
            'mfa_redirect': '/verify-mfa',
            'dashboard_redirect': '/dashboard'
        }), 200

    # Redirect to MFA verification page
    return redirect('/verify-mfa')


@app.route('/verify-mfa', methods=['GET', 'POST'])
@login_required
def verify_mfa():
    username = session['user']

    if session.get('mfa_verified'):
        if request.is_json:
            return jsonify({'message': 'MFA already verified'}), 200
        return redirect('/dashboard')

    if request.method == 'GET':
        return render_template_string(MFA_VERIFY_TEMPLATE)

    # Handle MFA verification
    if request.is_json:
        data = request.get_json()
        mfa_code = data.get('mfa_code', '').strip()
    else:
        mfa_code = request.form.get('mfa_code', '').strip()

    if not mfa_code:
        if request.is_json:
            return jsonify({'error': 'MFA code is required'}), 400
        return render_template_string(MFA_VERIFY_TEMPLATE, error='MFA code is required')

    # Get user's MFA secret
    secret = mfa_secrets.get(username)
    if not secret:
        if request.is_json:
            return jsonify({'error': 'MFA not configured for this user'}), 400
        return render_template_string(MFA_VERIFY_TEMPLATE, error='MFA not configured')

    # Verify the TOTP code
    if verify_totp(secret, mfa_code):
        session['mfa_verified'] = True
        session['mfa_verified_time'] = time.time()

        # Remove from pending
        pending_mfa.pop(username, None)

        if request.is_json:
            return jsonify({
                'message': 'MFA verification successful',
                'user': username,
                'mfa_verified': True,
                'redirect': '/dashboard'
            }), 200

        return redirect('/dashboard')
    else:
        if request.is_json:
            return jsonify({'error': 'Invalid MFA code'}), 401
        return render_template_string(MFA_VERIFY_TEMPLATE, error='Invalid MFA code. Please try again.')


@app.route('/verify-mfa-background', methods=['POST'])
@login_required
def verify_mfa_background():
    """Background MFA verification endpoint - can be called via AJAX."""
    username = session['user']

    if session.get('mfa_verified'):
        return jsonify({'message': 'MFA already verified', 'mfa_verified': True}), 200

    if request.is_json:
        data = request.get_json()
        mfa_code = data.get('mfa_code', '').strip()
    else:
        mfa_code = request.form.get('mfa_code', '').strip()

    if not mfa_code:
        return jsonify({'error': 'MFA code is required'}), 400

    secret = mfa_secrets.get(username)
    if not secret:
        return jsonify({'error': 'MFA not configured'}), 400

    if verify_totp(secret, mfa_code):
        session['mfa_verified'] = True
        session['mfa_verified_time'] = time.time()
        pending_mfa.pop(username, None)
        return jsonify({
            'message': 'MFA verified successfully in background',
            'mfa_verified': True
        }), 200
    else:
        return jsonify({'error': 'Invalid MFA code', 'mfa_verified': False}), 401


