@app.route('/logout', methods=['GET', 'POST'])
def logout():
    username = session.get('user')
    if username:
        pending_mfa.pop(username, None)
    session.clear()

    if request.is_json:
        return jsonify({'message': 'Logged out successfully'}), 200

    return redirect('/login?message=Logged out successfully')


